function LBattleLogicUnit:DoBuffUpdate(buff,etype)
    if not buff then return end

    local index = nil
    for i, buffData in ipairs(self.buffList) do
        if buffData.buffUniqueId == buff.buffUniqueId then
            index = i
            break
        end
    end

    if etype == LFightConst.BUFF_TYPE_ADD or etype == LFightConst.BUFF_TYPE_UPDATE then
        if index then
            self.buffList[index] = buff
        else
            table.insert(self.buffList,buff)
        end
    elseif etype == LFightConst.BUFF_TYPE_REMOVE then
        if index then
            table.remove(self.buffList,index)
        end
    end


    self:RefreshRelativeData()

    self:RefreshShowEffIndex()
end

function LBattleLogicUnit:RefreshRelativeData()
    local buffUIdMap = {}
    for k,v in pairs(self.buffList) do
        buffUIdMap[v.buffUniqueId] = true
    end
    local newList = {}

    for k, v in pairs(self.shieldList) do
        if buffUIdMap[v.buffUniqueId] then
            newList[v.shieldUniqueId] = v
        end
    end
    self.shieldList = newList


    newList = {}
    for k,v in pairs(self.angerList) do
        if buffUIdMap[v.buffUniqueId] then
            newList[v.buffUniqueId] = v
        end
    end

    self.angerList = newList

    newList = {}
    for k, v in ipairs(self.blockList) do
        if buffUIdMap[v.buffUniqueId] then
            table.insert(newList,v)
        end
    end

    self.blockList = newList

end

function LBattleLogicUnit:OnUpdateBuffRound(nowRound)
    for i, buff in ipairs(self.buffList) do
        local surplusRound = nowRound - buff.startRound
        if surplusRound < 0 then surplusRound = 0 end
        buff.currentRound = buff.round - surplusRound
    end
end

----------------------------------------------------------------------------
function LBattleLogicUnit:AddBlockData(blockData)
    table.insert(self.blockList,blockData)
end

function LBattleLogicUnit:RemoveBlockData(blockData)
    if not blockData then
        return
    end

    for i, v in ipairs(self.blockList) do
        if v.buffUniqueId == blockData.buffUniqueId then
            table.remove(self.blockList,i)
            break
        end
    end
end

function LBattleLogicUnit:UpdateBlockData()
    local block = self.blockList[1]    -- 优先扣除激活靠前的格挡盾次数
    if block then
        local curCount = block.curCount - 1
        if curCount > 0 then
            block.curCount = curCount
            self.blockList[1] = block
        else
            table.remove(self.blockList,1)
        end
    end
end

----------------------------------------------------------------------------
function LBattleLogicUnit:AddShieldData(shieldData)
    self.shieldList[shieldData.shieldUniqueId] = shieldData
end

function LBattleLogicUnit:RemoveShieldData(shieldData)
    if not shieldData then
        return
    end

    for i, v in pairs(self.shieldList) do
        if v.buffUniqueId == shieldData.buffUniqueId then
            self.shieldList[v.shieldUniqueId] = nil
            break
        end
    end
end

function LBattleLogicUnit:UpdateShieldData(shieldData)
    local shield = self.shieldList[shieldData.shieldUniqueId]
    if shield then
        local curHP = shield.curHP + shieldData.hurt
        if curHP <= 0 then
            self.shieldList[shieldData.shieldUniqueId] = nil
        else
            shield.curHP = curHP
        end
    end
end
