function LBattleLogicUnit:InitSkillData()

    local battleObjType = self.battleObjType
    if battleObjType == LFightConst.OBJ_NORMAL then
        self:InitRoleSkill()
        -- elseif battleObjType == LFightConst.OBJ_ARTIFACT then
        --     self:InitArtifactData()
    elseif battleObjType == LFightConst.OBJ_TREASURE then
        self:InitTreasureSkill()
    end
end

function LBattleLogicUnit:InitTreasureSkill()
    local skillList = self.skillList or {}
    self.skillRunDataList = {}
    self.skillIdToIndex = {}
    self.skillIdToSkin = {}
    local dataMgr = self._logicMgr:GetDataMgr()
    for k, v in ipairs(skillList) do
        local skillId = v.skillRefId
        local skinId = v.skin or 0
        self:AddSkillMap(tonumber(skillId),false,skinId)
        local cdRound = dataMgr:GetSkillCdRound(skillId)

        local isPlayed = v.initCD>=0
        local isPlaying = v.initCD == 1
        --local curCd = v.initCD - 1 --默认显示第一回合
        --curCd = curCd< 0 and cdRound or curCd
        local data =
        {
            index = v.index,
            skillId = skillId,
            cdRound = cdRound,
            curCd = v.initCD,
            isPlayed = isPlayed,
            isPlaying = isPlaying,
            state = v.state or 0,
            exhibitionInfo = v.exhibitionInfo,
            side = self.actOn,
            skin = skinId,
        }
        self.skillRunDataList[v.index] = data

        if skillId>0 then
            self.skillIdToIndex[skillId] = v.index
            self.skillIdToSkin[skillId] = skinId
        end
    end
    self.name = I18nText("2073", tostring(self.actOn))
end

function LBattleLogicUnit:Reset()
    if self.unitData then
        self.hp = self.unitData.hp
        self.maxHp = self.unitData.maxHp
        self._state = BattleUnitState.Idle
    else
        self.maxHp = 1
        self.hp = 1
        self._state = BattleUnitState.Idle
    end
end

function LBattleLogicUnit:InitRoleSkill()
    local refId = self.refId
    local objName = nil

    local dataMgr = self._logicMgr:GetDataMgr()

    local effectIdList = {}
    self.effectIdList = effectIdList

    if self.isMonster then
        local monRef = GameTable.MonsterAttrRef[refId]
        if not monRef then
            if LOG_INFO_ENABLED then
                printError("battle", "怪物数据不存在， refId="..tostring(refId))
            end
            return false
        end

        local effectId = nil
        if self.battleObjType == LFightConst.OBJ_SUMMON then
            effectId = dataMgr:GetSummonShowSkin(refId,self.belongSkin)
        end

        if not effectId then
            effectId = monRef.effectId
        end

        table.insert(effectIdList,effectId)

        local commandSkill = monRef.commonSkill
        self:AddSkillMap(commandSkill,true)

        local activeSkill = monRef.activeSkill
        if activeSkill then
            for i = 1,#activeSkill do
                local data = activeSkill[i]
                local temp = string.split(data,"=")
                local skillId = tonumber(temp[1] or 0 ) or 0
                if skillId > 0 then
                    self:AddSkillMap(skillId)
                end
            end
        end

        local belongSkillList = monRef.belongSkillGroup
        if belongSkillList then
            for i = 1,#belongSkillList do
                local skillId = tonumber(belongSkillList[i])
                if skillId  then
                    if skillId > 0 then
                        self:AddSkillMap(skillId)
                    end
                else
                    if LOG_INFO_ENABLED then
                        printError("battle", "怪物技能错误,refId="..tostring(refId))
                    end
                end
            end
        end

        local pasvSkill = monRef.pasvSkil
        if pasvSkill then
            for i = 1,#pasvSkill do
                local skillId = tonumber(pasvSkill[i] or 0 ) or 0
                if skillId > 0 then
                    self:AddSkillMap(skillId)
                end
            end
        end

        objName = I18nText(monRef.name)

        if string.isempty(objName) then
            local heroEffRef = GameTable.CharacterEffectRef[effectId]
            if  heroEffRef then
                objName = I18nText(heroEffRef.name)
            else
                if LOG_INFO_ENABLED then
                    printError("battle", "怪物表现数据不存在, refId="..tostring(effectId))
                end
            end
        end
    else
        local starLv = self.star
        local ref = GameTable.CharacterRef[refId]
        if not ref then
            return
        end


        local form = self.form

        local starRef = dataMgr:GetHeroStarRef(refId,form,starLv)
        --
        --if not starRef then return end

        local heroEffectId = nil
        if self.skinId and self.skinId>0 then
            heroEffectId = self.skinId
        else
            --heroEffectId = starRef.effectId
            heroEffectId = refId
        end

        table.insert(effectIdList,heroEffectId)

        local heroEffRef = GameTable.CharacterEffectRef[heroEffectId]

        if heroEffRef.skinState2 and heroEffRef.skinState2 > 0 then
            table.insert(effectIdList,heroEffRef.skinState2)
        end

        local skillList = starRef.skillGroup
        if skillList then
            for i = 1,#skillList do
                local data = skillList[i]
                local temp = string.split(data,"=")
                local skillId = tonumber(temp[1] or 0 ) or 0
                if skillId > 0 then
                    self:AddSkillMap(skillId)
                end
            end
        end

        local belongSkillList = starRef.belongSkillGroup
        if belongSkillList then
            for i = 1,#belongSkillList do
                local skillId = tonumber(belongSkillList[i])
                if skillId > 0 then
                    self:AddSkillMap(skillId)
                end
            end
        end

        local commandSkill = starRef.commonSkill
        self:AddSkillMap(commandSkill,true)

        objName = I18nText(heroEffRef.name)
    end
    self.name = objName

end

