---@return LBattleSkillData
function LBattleLogicUnit:GetSkillData(skillId,skillExpressionRefId,attackCount)
    local dataMgr = self._logicMgr:GetDataMgr()
    local expressionId = dataMgr:GetSkillExpressionId(skillExpressionRefId,attackCount)
    if not expressionId then return end

    local skillType = nil
    local isTreasure = self.battleObjType == LFightConst.OBJ_TREASURE
    local skinId = nil
    local expressId = nil
    if isTreasure then
        skinId = self.skillIdToSkin[skillId]
        expressId = dataMgr:GetTreasureSkinExpress(skinId,expressionId)
    else
        skinId = self:GetShowEffId()
        expressId = dataMgr:GetSkinExpress(skinId,expressionId,true)

        skillType = dataMgr:GetSkinSkillType(skinId,expressionId)
    end

    local dataMap =  self.skillDataMap[expressId]
    local data = nil
    if dataMap  then
        data = dataMap[skillId]
        if data then
            return data
        end
    end
    --读取通用技能
    data = dataMgr:GetGeneralSkillData(expressId)
    if not data then
        data = dataMgr:GetSkillDataCommon(skillId,expressId,skinId,skillType)
    end
    return data
end

function LBattleLogicUnit:GetSkillTransformData(skillId,expressId,expressionRefId)
    local dataMgr = self._logicMgr:GetDataMgr()

    local dataMap =  self.skillDataMap[expressId]
    local data = nil
    if dataMap  then
        data = dataMap[skillId]
        if data then
            return data
        end
    end

    --读取通用技能
    data = dataMgr:GetGeneralSkillData(expressId)

    if not data then
        local skinId = self:GetShowEffId()
        data = dataMgr:GetSingleSkillData(skillId,expressId,skinId,expressionRefId)
    end
    return data
end

function LBattleLogicUnit:AddSkillMap(skillId,bNormal,skinId)

    local dataMgr = self._logicMgr:GetDataMgr()

    self:AddReliveSkillRecord(skillId)


    skinId = skinId or self:GetSkinId()

    local skillExpressList = dataMgr:GetExpressionList(skillId)
    for k,v in ipairs(skillExpressList) do
        self:ParsePlaySkillID(skillId,v,bNormal,skinId)
    end
end

function LBattleLogicUnit:ParsePlaySkillID(skillId,expressData,bNormal,skinId)
    local dataMgr = self._logicMgr:GetDataMgr()

    local expressionList = dataMgr:GetSkillPlayEffList(expressData.expressionId)
    if not expressionList then
        return
    end

    local isRole = self.battleObjType == LFightConst.OBJ_NORMAL
    local isTreasure = self.battleObjType == LFightConst.OBJ_TREASURE
    --  local skinId = self:GetSkinId()

    for k,v in ipairs(expressionList) do

        local skillType = nil
        local expressId = nil
        if isTreasure then
            expressId = dataMgr:GetTreasureSkinExpress(skinId,v)
        else
            expressId = dataMgr:GetSkinExpress(skinId,v)

            skillType = dataMgr:GetSkinSkillType(skinId,v)
        end

        local skillData = LBattleSkillData:new(dataMgr)
        skillData:SetSkinSkillType(skillType)
        if skillData:InitData(skillId,expressData.skillEffId,expressId,bNormal,skinId) then
            if isTreasure then
                skillData:SetTreasureSkin(skinId)
            end

            local dataMap = self.skillDataMap[expressId]
            if not dataMap then
                dataMap = {}
                self.skillDataMap[expressId] = dataMap
            end
            dataMap[skillId]= skillData
            self.skillDataMap[expressId] = skillData
        end
    end
end

function LBattleLogicUnit:AddReliveSkillRecord(skillId)
    local dataMgr = self._logicMgr:GetDataMgr()

    if not self.reliveSkillRecord  then
        self.reliveSkillRecord = {}
    end

    local record = self.reliveSkillRecord

    local reliveType = dataMgr:GetReliveSkillType(skillId)
    if reliveType>0 then
        local map = record[self.id]
        if not map then
            map = {}
            record[self.id] = map
        end
        map[reliveType] = true
    end
end

function LBattleLogicUnit:GetReliveSkillRecord()
    return self.reliveSkillRecord or {}
end

function LBattleLogicUnit:ToHpString()
    local str = string.format("id=%s, refId=%s, maxHp=%s, hp=%s, dead=%s, damage=%s, bedamage=%s",
            tostring(self.id),tostring(self.refId),tostring(self.maxHp),tostring(self.hp),tostring(self.isDead),
            tostring(self.damageCount),tostring(self.bearDamageCount))
    return str
end

