function LBattleLogicUnit:OnRoundUpdate(round) --下一回合
    if self.battleObjType ~= LFightConst.OBJ_TREASURE then
        return
    end
    if round<=self.curRound then
        return
    end

    self.curRound = round

    for k,v in pairs(self.skillRunDataList) do
        if v.isPlayed then
            local cd = v.curCd -1
            v.isPlaying = cd == 1
            v.curCd = cd
        end
    end


end

function LBattleLogicUnit:GenTreasureCd(skillRefId)
    if self.battleObjType ~= LFightConst.OBJ_TREASURE then
        return
    end
    local index = self.skillIdToIndex[skillRefId]
    if index then
        local data = self.skillRunDataList[index]
        data.isPlayed = true
        if data.curCd <=0 then
            data.curCd = data.cdRound
        end
    end
    return true
end

--后台战斗不会调用
function LBattleLogicUnit:OnTreasureSkillEnd(skillRefId)
    if self.battleObjType ~= LFightConst.OBJ_TREASURE then
        return
    end
    local index = self.skillIdToIndex[skillRefId]
    if index then
        local data = self.skillRunDataList[index]
        data.isPlaying = false
    end

    FireEvent(EventNames.BATTLE_SKILL_LIST_UPDATE)
end

function LBattleLogicUnit:GetSkillIndex(skillRefId)
    if self.battleObjType ~= LFightConst.OBJ_TREASURE then
        return 1
    end
    local index = self.skillIdToIndex[skillRefId]
    return index
end

function LBattleLogicUnit:GetSkillRunDataList()
    return self.skillRunDataList or {}
end

function LBattleLogicUnit:GetTeamName()
    return self.teamName
end

function LBattleLogicUnit:RefreshShowEffIndex()
    local showEffIndex = 1
    local isChangeSpine = false
    for k,v in ipairs(self.buffList) do
        local buffRef = GameTable.CombatBuffRef[v.buffId]
        if buffRef then
            if buffRef.specialShow == 1 then
                showEffIndex = 2

                if not isChangeSpine then
                    if v.round > 0 then
                        isChangeSpine = true
                    end
                end

            end
        end
    end

    self.isChangeSpine = isChangeSpine
    self.showEffectIndex = showEffIndex
end

function LBattleLogicUnit:GetShowEffId()
    local index = self.showEffectIndex or 1
    local effId = self.effectIdList[index]
    if not effId then
        effId = self.effectIdList[1]
    end
    return effId
end

---@param baseEffect LBattleBaseEffectData
function LBattleLogicUnit:UpdateRoundData(baseEffect)
    local buffEffectData = baseEffect.buffEffect
    local buffUniqueId = buffEffectData.buffUniqueId
    local round = buffEffectData.round
    for k, v in ipairs(self.buffList) do
        if v.buffUniqueId == buffUniqueId then
            v.round = round
            break
        end
    end
end

---- 获取战斗音效
---1. 战斗默认音效填写战斗表现表（普攻、技1、技2）——根据表格填写读取，和原规则一致
---2. 战斗进阶语音，好感度解锁技能1、技能2的，达到好感度默认使用
---根据HeroFavorabilityRef的等级判断，是否解锁战斗语音SpActionSound列填写的：skillSound1、skillSound2
---如果解锁，则使用HeroEffectRef的skillSound1、skillSound2列填写的语音文件
---3. 战斗皮肤语音，根据表现表配置，穿戴皮肤后默认使用——优先级高于进阶语音，和原规则一致
function LBattleLogicUnit:GetPlaySoundBattle(soundBattle,effData)
    local dataMgr = self._logicMgr:GetDataMgr()
    local skinId = self.skinId
    if skinId and skinId > 0 then
        if not dataMgr:GetHeroOriginId(skinId) then
            --- 穿戴是皮肤，由 skill 表配置的音效
            return soundBattle
        end
    end

    if not self.loveLevel then return soundBattle end

    --local ref = GameTable.CharacterFavorabilityRef[self.loveLevel]
    --if not ref then return soundBattle end
    --
    --local SpActionSound = ref.SpActionSound
    --if SpActionSound == "skillSound1" or SpActionSound == "skillSound2" then
    --    local effRef = gModelHero:GetHeroShowEffectRef(self.refId,self.star,skinId,self.form)
    --    if effRef then
    --        soundBattle = effRef[SpActionSound]
    --    end
    --end

    local favorabilykey = dataMgr:GetHeroFavorabilitySounds(self.loveLevel,effData)
    if favorabilykey then
        local effRef = dataMgr:GetHeroShowEffectRef(self.refId,self.star,skinId,self.form)
        if effRef then
            if LOG_INFO_ENABLED then
                printInfo("battle",string.format("好感度等级：%s, 原音效名字：%s, 修改后音效名字：%s, 索引的key：%s",  tostring(self.loveLevel),
                        tostring(soundBattle) , tostring(effRef[favorabilykey]), tostring(favorabilykey) ))
            end
            soundBattle = effRef[favorabilykey]
        end
    end
    return soundBattle
end


function LBattleLogicUnit:GetHeroRaceType()
    local dataMgr = self._logicMgr:GetDataMgr()

    local skinId = self:GetSkinId()
    local heroEff = GameTable.CharacterEffectRef[skinId]
    if not heroEff then return 1 end

    local heroRef = GameTable.CharacterRef[heroEff.heroType]
    return heroRef and heroRef.raceType or 1
end


function LBattleLogicUnit:IsHeroType()
    return self.battleObjType == LFightConst.OBJ_NORMAL
end


